{
    public class Sample1_ComputeLimit
    {
        [Test]
        [Ignore(&#34;Only verifying that the sample compiles&#34;)]
        public async Task ListVmFamilies()
        {
            #region Snippet:ComputeLimit_ListVmFamilies
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            AzureLocation location = AzureLocation.EastUS;

            ComputeLimitVmFamilyCollection vmFamilies = subscription.GetComputeLimitVmFamilies(location);
            await foreach (ComputeLimitVmFamilyResource vmFamily in vmFamilies.GetAllAsync())
            {
                Console.WriteLine($&#34;VM Family: {vmFamily.Data.Name}&#34;);
            }
            #endregion
        }

        [Test]
        [Ignore(&#34;Only verifying that the sample compiles&#34;)]
        public async Task EnableFeature()
        {
            #region Snippet:ComputeLimit_EnableFeature
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            AzureLocation location = AzureLocation.EastUS;

            ComputeLimitFeatureCollection features = subscription.GetComputeLimitFeatures(location);
            await foreach (ComputeLimitFeatureResource feature in features.GetAllAsync())
            {
                Console.WriteLine($&#34;Feature: {feature.Data.Name}, State: {feature.Data.Properties?.State}&#34;);
            }
            #endregion
        }

        [Test]
        [Ignore(&#34;Only verifying that the sample compiles&#34;)]
        public async Task ManageSharedLimits()
        {
            #region Snippet:ComputeLimit_ManageSharedLimits
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            AzureLocation location = AzureLocation.EastUS;

            // Retrieve existing shared limits
            ComputeLimitSharedLimitCollection sharedLimits = subscription.GetComputeLimitSharedLimits(location);
            await foreach (ComputeLimitSharedLimitResource sharedLimit in sharedLimits.GetAllAsync())
            {
                Console.WriteLine($&#34;Shared Limit: {sharedLimit.Data.Name}&#34;);
            }

            // List guest subscriptions for this host
            ComputeLimitGuestSubscriptionCollection guestSubscriptions = subscription.GetComputeLimitGuestSubscriptions(location);
            await foreach (ComputeLimitGuestSubscriptionResource guest in guestSubscriptions.GetAllAsync())
            {
                Console.WriteLine($&#34;Guest Subscription: {guest.Data.Name}&#34;);
            }
            #endregion
        }
    }
}
```

Then add snippet placeholders in the README at the Examples section for each snippet name:
- `ComputeLimit_ListVmFamilies`
- `ComputeLimit_EnableFeature`
- `ComputeLimit_ManageSharedLimits`

### Step 3: Verify README structure

The README at `sdk/computelimit/Azure.ResourceManager.ComputeLimit/README.md` currently has all required sections but the following need content improvements:

1. **Key concepts** — currently generic; replace with package-specific resource type table (see Step 1)
2. **Examples** — currently generic links only; replace with actual code snippet placeholders (see Step 1)

Sections present and adequate:
- Getting started (Install the package ✅, Prerequisites ✅, Authenticate the client ✅)
- Troubleshooting ✅
- Next steps ✅
- Contributing ✅

### Step 4: Validate

Run these commands in order:

1. `dotnet build sdk/computelimit/Azure.ResourceManager.ComputeLimit/`
2. `dotnet test sdk/computelimit/Azure.ResourceManager.ComputeLimit/ --filter TestCategory!=Live`
3. `eng/scripts/Update-Snippets.ps1 computelimit` — injects snippet code into README placeholders; verify README diff shows code was injected
4. `eng/scripts/Export-API.ps1 computelimit` — no public API changes expected, but run to confirm
5. `dotnet format sdk/computelimit/Azure.ResourceManager.ComputeLimit/`



